const fs=require('fs');
const root=$input.first().json||{};
const b=root.body||root;
const af=b.all_fields||{};
const data=af.data||{};
const rule=af.rule||{};
const agent=af.agent||{};
const asrc=data.alerte_source||{};
let srcip=String(data.srcip||b.srcip||'').trim();
let agent_id=String((agent.id!==undefined?agent.id:'')||b.agent_id||'').trim();
let level=Number(rule.level||asrc.level||b.level||0);
let desc=String(rule.description||asrc.description||b.desc||'').slice(0,200);
let rule_id=String(rule.id||asrc.rule_id||b.rule_id||'').trim();
let alert_id=String(af.id||asrc.alert_id||data.id||b.id||'').trim();
const isWrap=!!(data&&data.deepseek)||String((rule&&rule.id)||'')==='100100';
let ts=isWrap?String(asrc.timestamp||'').trim():String(af.timestamp||data.timestamp||b.timestamp||'').trim();
const ipValid=(x)=>/^\d{1,3}(\.\d{1,3}){3}$/.test(x)&&x.split('.').every(o=>+o>=0&&+o<=255);
const ALWAYS=['100.73.179.63','100.67.35.26'];
const TS=['100.101.128.76','100.101.80.37'];
const inLAN=(x)=>x.startsWith('192.168.0.');
if(level<10||!srcip||!ipValid(srcip))return [];
if(ALWAYS.includes(srcip)||inLAN(srcip)||TS.includes(srcip))return [];
if(!['001','002'].includes(agent_id))return [];
const f='/home/node/.n8n/soar_seen_'+srcip.replace(/\./g,'_');
try{const t=parseInt(String(fs.readFileSync(f,'utf8')).trim(),10);if(Date.now()-t<300000)return [];}catch(e){}
try{fs.writeFileSync(f,String(Date.now()));}catch(e){}
try{ fs.appendFileSync('/home/node/.n8n/soar_validations.jsonl', JSON.stringify({type:'request',exec:(($execution&&$execution.id)||''),ip:srcip,agent:agent_id,level,rule:(rule_id+' '+desc).trim(),ts:new Date().toISOString()})+'\n'); }catch(e){}
return [{json:{srcip,agent_id,level,desc,rule_id,ts,alert_id}}];

const j=$input.first().json||{};
const q=j.query||j.body||j||{};
let v=(q.approved!==undefined)?q.approved:j.approved;
const approved=String(v).toLowerCase()==='true';
try{ const ff=$('Filter').first().json||{}; require('fs').appendFileSync('/home/node/.n8n/soar_validations.jsonl', JSON.stringify({type:'decision',exec:(($execution&&$execution.id)||''),ip:ff.srcip,result:approved?'approved':'refused',ts:new Date().toISOString()})+'\n'); }catch(e){}
return [{json:{approved}}];
